SELECT v.name AS venueName, v.location AS location, COUNT(b.id) AS usageCount FROM booking b INNER JOIN venue v ON b.venue_id = v.id WHERE b.status IN ('confirmed', 'completed')
AND b.schedule_date >= #{startDate}
AND b.schedule_date <= #{endDate}
GROUP BY b.venue_id, v.name, v.location ORDER BY usageCount DESC

SELECT b.coach_id AS coachId, u.nickname AS coachName, COUNT(b.id) AS classCount FROM booking b INNER JOIN sys_user u ON b.coach_id = u.id WHERE b.status IN ('confirmed', 'completed')
AND b.schedule_date >= #{startDate}
AND b.schedule_date <= #{endDate}
GROUP BY b.coach_id, u.nickname ORDER BY classCount DESC

SELECT b.student_id AS studentId, u.nickname AS studentName, COUNT(b.id) AS classCount FROM booking b INNER JOIN sys_user u ON b.student_id = u.id WHERE b.status IN ('confirmed', 'completed')
AND b.schedule_date >= #{startDate}
AND b.schedule_date <= #{endDate}
GROUP BY b.student_id, u.nickname ORDER BY classCount DESC
